const f = $input.first().json;
const name = (f['Influencer Name'] || '').trim();
const handle = (f['Instagram Handle'] || '').trim();
const niche = (f['Niche'] || '').trim();
const gender = (f['Gender'] || '').trim();
const age = (f['Age'] || '').trim();
const location = (f['Location'] || '').trim();
const personality = (f['Personality Vibe'] || '').trim();
const aesthetic = (f['Visual Aesthetic'] || '').trim();
const physical = (f['Specific Physical Description'] || '').trim();
const email = (f['Your Email'] || '').trim();
const physicalDesc = physical || ('A ' + age + '-year-old ' + gender.toLowerCase() + ' from ' + location + ' with an attractive, photogenic appearance suitable for a ' + niche.toLowerCase() + ' influencer.');

return [{ json: { name, handle, niche, gender, age, location, personality, aesthetic, physicalDesc, email, timestamp: new Date().toISOString() } }];

// ============================================================
// ENHANCEMENT 1: TREND & FESTIVAL INTELLIGENCE LAYER (v3 NEW)
// Injects Indian festival awareness + niche trending hashtags
// into the calendar generation prompt for timely, discoverable content.
// No API call needed — zero cost. Pure Code node.
// ============================================================

const d = $input.first().json;

// Hardcoded Indian festival calendar (approximate annual dates)
var festivals = [
  { name: 'Pongal', month: 1, day: 14 },
  { name: 'Republic Day', month: 1, day: 26 },
  { name: 'Holi', month: 3, day: 14 },
  { name: 'Eid ul-Fitr', month: 3, day: 31 },
  { name: 'Ram Navami', month: 4, day: 6 },
  { name: 'Independence Day', month: 8, day: 15 },
  { name: 'Janmashtami', month: 8, day: 26 },
  { name: 'Ganesh Chaturthi', month: 8, day: 27 },
  { name: 'Navratri', month: 10, day: 2 },
  { name: 'Dussehra', month: 10, day: 12 },
  { name: 'Diwali', month: 10, day: 20 },
  { name: 'Bhai Dooj', month: 10, day: 22 },
  { name: 'Christmas', month: 12, day: 25 },
  { name: 'New Year Eve', month: 12, day: 31 }
];

var today = new Date();
var endDate = new Date(today);
endDate.setDate(today.getDate() + 30);

// Find festivals in the next 30-day window
var upcoming = [];
festivals.forEach(function(f) {
  var festDate = new Date(today.getFullYear(), f.month - 1, f.day);
  if (festDate >= today && festDate <= endDate) {
    var dayNum = Math.ceil((festDate - today) / (1000 * 60 * 60 * 24));
    upcoming.push(f.name + ' (around Day ' + dayNum + ')');
  }
});

// Niche-specific trending hashtag clusters
var nicheHashtags = {
  'Fitness & Wellness': '#FitnessChallenge #WellnessTrends #GymLife #HealthFirst #FitIndia #ActiveLiving #MindBodyBalance',
  'Fashion & Lifestyle': '#OOTD #FashionTrends #StyleInspo #IndianFashion #StreetStyle #FashionBlogger #OutfitOfTheDay',
  'Travel & Adventure': '#ExploreIndia #TravelDiaries #WeekendGetaway #HiddenGems #TravelBlogger #IncredibleIndia #Wanderlust',
  'Tech & Productivity': '#TechTips #AITools #ProductivityHacks #StartupIndia #FutureOfWork #TechBlogger #DigitalIndia',
  'Food & Cooking': '#HomeCooking #FoodieIndia #RecipeOfTheDay #MealPrep #InstaFood #FoodBlogger #IndianCuisine',
  'Beauty & Skincare': '#SkincareRoutine #CleanBeauty #IndianSkincare #GlowUp #BeautyTips #SkincareCommunity #BeautyBlogger',
  'Finance & Business': '#PersonalFinance #StartupLife #InvestingInIndia #FinancialFreedom #MoneyMindset #WealthBuilding #FinanceBlogger',
  'Motivation & Mindset': '#MondayMotivation #GrowthMindset #DailyInspiration #SelfImprovement #MindsetMatters #PositiveVibes #MotivationDaily'
};

var hashtags = nicheHashtags[d.niche] || '#trending #viral #explore #india #content';

// Build the trend context string injected into calendar prompt
var trendContext = '';

if (upcoming.length > 0) {
  trendContext += 'UPCOMING INDIAN FESTIVALS IN THE NEXT 30 DAYS: ' + upcoming.join(', ') + '. ';
  trendContext += 'IMPORTANT: Include at least one festival-themed content post near each relevant festival date listed above. The post should feel authentic and celebratory, not forced. ';
}

trendContext += 'TRENDING HASHTAGS FOR ' + (d.niche || 'this niche').toUpperCase() + ': ' + hashtags + '. ';
trendContext += 'Weave 2-3 of these trending hashtags naturally into relevant calendar posts. ';
trendContext += 'Include 2-3 posts that tie into current seasonal moments, trending topics, or viral challenges popular in India right now. ';
trendContext += 'Make the content feel current, timely, and discoverable — not generic or evergreen only.';

return [{ json: Object.assign({}, d, { trendContext: trendContext }) }];

const aiResp = $input.first().json;
const form = $('🔧 Parse Brief1').first().json;
let character = {};
try {
  const raw = aiResp?.message?.content || '{}';
  character = JSON.parse(raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch (e) {
  character = {
    bio: form.niche + ' creator from ' + form.location,
    backstory: form.name + ' is a ' + form.age + '-year-old ' + form.niche.toLowerCase() + ' enthusiast from ' + form.location + '.',
    personality_traits: ['authentic', 'motivating', 'creative', 'relatable', 'energetic'],
    content_pillars: ['Tips', 'Day in Life', 'Inspiration', 'Behind the Scenes'],
    caption_style: 'Casual, warm, 1-2 emojis, ends with a question.',
    signature_elements: 'Consistent hairstyle, signature color, always smiling',
    target_audience: '18-30 year olds interested in ' + form.niche.toLowerCase(),
    master_prompt: 'A photorealistic portrait of ' + form.physicalDesc + '. ' + form.aesthetic + '. Shot on Canon EOS R5, 85mm lens, shallow depth of field, Instagram lifestyle photography.',
    hashtag_bank: ['#ai', '#influencer', '#content', '#lifestyle', '#trending']
  };
}
return [{ json: { ...form, character } }];

const aiResp = $input.first().json;
const prev = $('🔀 Parse Character').first().json;
let days1to15 = [];
try {
  const raw = aiResp?.message?.content || '[]';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  days1to15 = Array.isArray(parsed) ? parsed : (parsed.calendar || parsed.days || []);
} catch (e) {
  days1to15 = [];
}
return [{ json: { ...prev, days1to15 } }];

const aiResp = $input.first().json;
const prev = $('🔀 Parse Days 1-15').first().json;
let days16to30 = [];
try {
  const raw = aiResp?.message?.content || '[]';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  days16to30 = Array.isArray(parsed) ? parsed : (parsed.calendar || parsed.days || []);
} catch (e) {
  days16to30 = [];
}
const fullCalendar = [...(prev.days1to15 || []), ...days16to30];
return [{ json: { ...prev, days1to15: undefined, calendar: fullCalendar } }];

const aiResp = $input.first().json;
const prev = $('🔀 Merge Full Calendar').first().json;
let extras = {};
try {
  const raw = aiResp?.message?.content || '{}';
  extras = JSON.parse(raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch (e) {
  extras = { carousels: [], brand_pitches: [] };
}
return [{ json: { ...prev, carousels: extras.carousels || [], brandPitches: extras.brand_pitches || [] } }];

const d = $input.first().json;
const cal = d.calendar || [];

if (cal.length === 0) {
  return [{ json: { ...d, calendarRows: [] } }];
}

const rows = cal.map(day => ({
  day: day.day || '',
  type: day.type || '',
  photo_description: day.photo_description || '',
  ideogram_prompt: day.ideogram_prompt || '',
  caption: day.caption || '',
  hashtags: day.hashtags || '',
  posting_time: day.posting_time || '',
  status: 'Not Generated'
}));

return [{ json: { ...d, calendarRows: rows } }];

const d = $input.first().json;
const rows = d.calendarRows || [];
const name = d.name;
const handle = d.handle;

if (rows.length === 0) return [];

return rows.map(row => ({ json: {
  Influencer: name + ' (' + handle + ')',
  'Day': row.day,
  'Type': row.type,
  'Photo Description': row.photo_description,
  'Ideogram Prompt': row.ideogram_prompt,
  'Caption': row.caption,
  'Hashtags': row.hashtags,
  'Posting Time': row.posting_time,
  'Image Status': 'Not Generated',
  'Video Status': 'Not Generated',
  'Posted': 'No'
} }));

const d = $('📊 Prepare Calendar Rows').first().json;
const c = d.character;
const cal = d.calendar || [];
const carousels = d.carousels || [];
const pitches = d.brandPitches || [];

let calText = '';
cal.forEach(day => {
  calText += '
--- DAY ' + day.day + ' (' + day.type + ') ---
Photo: ' + day.photo_description + '

IDEOGRAM PROMPT (copy-paste this):
' + day.ideogram_prompt + '

CAPTION:
' + day.caption + '

HASHTAGS: ' + day.hashtags + '
BEST TIME: ' + day.posting_time + '
';
});

let carText = '';
carousels.forEach((car, i) => {
  carText += '
=== CAROUSEL ' + (i+1) + ': ' + car.title + ' ===
';
  (car.slides || []).forEach(s => { carText += 'Slide ' + s.slide_num + ': ' + s.headline + '
  ' + s.body + '
'; });
});

let pitchText = '';
pitches.forEach((p, i) => {
  pitchText += '
=== PITCH ' + (i+1) + ': ' + p.brand_type + ' ===
Subject: ' + p.subject + '

' + p.body + '
';
});

const megaEmail = '🤖 YOUR AI INFLUENCER IS READY: ' + d.name + ' (' + d.handle + ')

' + '='.repeat(50) + '
CHARACTER SHEET
' + '='.repeat(50) + '
Bio: ' + c.bio + '
Backstory: ' + c.backstory + '
Personality: ' + (c.personality_traits||[]).join(', ') + '
Content Pillars: ' + (c.content_pillars||[]).join(', ') + '
Caption Style: ' + c.caption_style + '
Signature Elements: ' + c.signature_elements + '
Target Audience: ' + c.target_audience + '

MASTER IDEOGRAM PROMPT:
' + c.master_prompt + '

HASHTAG BANK:
' + (c.hashtag_bank||[]).join(' ') + '

' + '='.repeat(50) + '
30-DAY CALENDAR (' + cal.length + ' days generated)
' + '='.repeat(50) + '
' + calText + '

' + '='.repeat(50) + '
CAROUSEL SCRIPTS
' + '='.repeat(50) + '
' + carText + '

' + '='.repeat(50) + '
BRAND PITCH EMAILS
' + '='.repeat(50) + '
' + pitchText + '

' + '='.repeat(50) + '
NEXT STEPS
' + '='.repeat(50) + '
1. Open your Google Sheet — Calendar tab has 1 row per day
2. Image Status column will auto-update with generated image URLs (v3 Ideogram API integration)
3. For video: open Pixverse, upload the generated image, generate 5-sec clip
4. Open Canva for carousels, CapCut for reels
5. Post to Instagram with the caption and hashtags from the sheet
6. Update Video Status and Posted columns as you go

Total API cost this run: ~INR 15-30 (GPT) + ~INR 50-200 (Ideogram). Your AI influencer is ready to go live.';

return [{ json: { ...d, megaEmail } }];

// ENHANCEMENT 1: Parse Ideogram API response and extract image URL
// Merges response URL back with the original batch item's Influencer + Day data
// for the Google Sheets update that follows.

const response = $input.first().json;
const batchItem = $('🔢 SplitInBatches (Ideogram)').item.json;

let imageUrl = 'Generation Failed';
try {
  if (response && response.data && response.data[0]) {
    imageUrl = response.data[0].url || response.data[0].imageUrl || 'Generation Failed';
  }
} catch(e) {
  imageUrl = 'Generation Failed';
}

return [{ json: {
  Influencer: batchItem.Influencer || '',
  Day: batchItem.Day || '',
  'Image Status': imageUrl
} }];
